+    /// Views: CREATE VIEW, SELECT from view, view with JOINs.
+    #[test]
+    fn test_conformance_views_v2() {
+        let fconn = Connection::open(":memory:").unwrap();
+        let rconn = rusqlite::Connection::open_in_memory().unwrap();
+
+        let setup = [
